// Long + track cycle every 2 days (Jan 1 main -> Jan 3 main ...). Each short uses the next 1/3 of the same track audio.
// Short YouTube publish times vs publish_at_iso (main): +12h, +24h, +40h (example: main Jan 1 00:00 UTC -> shorts Jan 1 12:00, Jan 2 00:00, Jan 2 16:00).
// Set publish_at_iso to your real main slot (cron alone is not midnight).
const tracks = [
  '01-example-track.mp3',
  '02-example-track.mp3'
];
const themes = ['Lake Meditation', 'Ocean Calm'];
const tagSets = [
  ['nature', 'forest', 'lofi'],
  ['ocean', 'waves', 'chill']
];

const anchor = Date.parse('2026-01-01T00:00:00Z');
const now = Date.now();
const elapsedDays = Math.floor((now - anchor) / (24 * 60 * 60 * 1000));

if (elapsedDays % 2 !== 0) {
  return [];
}

const cycleIndex = Math.floor(elapsedDays / 2) % tracks.length;

return [{
  json: {
    track: tracks[cycleIndex],
    allow_recent_preferred: false,
    tags: tagSets[cycleIndex % tagSets.length],
    theme: themes[cycleIndex % themes.length],
    publish_at_iso: new Date().toISOString(),
    shorts_count: 3,
    short_publish_offset_hours: [12, 24, 40],
    shorts_use_main_track_thirds: true,
    clip_seconds: 30,
    main_privacy_status: 'public',
    shorts_privacy_status: 'private',
    cleanup_source_after_publish: true,
    cleanup_shorts_after_upload: true
  }
}];
